output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?team ?teamLabel ?city ?cityLabel ?stadium ?stadiumLabel ?population WHERE {
  ?team wdt:P31 wd:Q5134 .
  ?team wdt:P151 wd:Q155223 .
  ?team wdt:P131 ?city .
  ?city wdt:P1082 ?population .
  ?team wdt:P1892 ?stadium .
  OPTIONAL {
    ?team rdfs:label ?teamLabel .
    FILTER(lang(?teamLabel) = 'en')
  }
  OPTIONAL {
    ?city rdfs:label ?cityLabel .
    FILTER(lang(?cityLabel) = 'en')
  }
  OPTIONAL {
    ?stadium rdfs:label ?stadiumLabel .
    FILTER(lang(?stadiumLabel) = 'en')
  }
}

